understanding_checks.code:
from dataclasses import dataclass

@dataclass
class Product:
    price: float

    def __post_init__(self):
        if self.price < 0:
            self.price = 0.0

p = Product(-50)
print(p.price)

from dataclasses import dataclass

@dataclass
class Circle:
    radius: float
    area: float

    def __post_init__(self):
        self.area = 3.14 * (self.radius ** 2)

c = Circle(2.0)
print(c.area)

code_walkthrough.code:
from dataclasses import dataclass, field

@dataclass
class User:
    username: str
    is_admin: bool = field(init=False)

    def __post_init__(self):
        self.is_admin = self.username.startswith('admin_')

u = User('admin_alice')
print(u.is_admin)

