from dataclasses import dataclass

@dataclass
class Rectangle:
    width: int
    height: int

    def __post_init__(self):
        print(f'Validating {self.width}x{self.height}')
        if self.width <= 0:
            raise ValueError('Width must be positive')

Rectangle(10, 5)

